export function searchScenarios(q){const s=new Map();const w=q.split(/\s+/);for(const[k,ix]of Object.entries(K)){for(const ww of w){if(k.includes(ww)||ww.includes(k)){for(const i of ix)s.set(i,(s.get(i)||0)+1)}}}const r=[...s.entries()].sort((a,b)=>b[1]-a[1]).slice(0,3).map(([i])=>({situation:S[i],...M[i]}));return r.length?r:M.slice(0,3).map((m,i)=>({situation:S[i],...m}))}
